import{_ as e,c as o,o as i,a1 as r}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Funcionalidades da Plataforma: Revisão de Planos e Código | Plannotator","description":"Aprenda as funcionalidades da plataforma Plannotator, incluindo revisão de planos e revisão de código. Domine habilidades essenciais como revisão visual, adição de anotações e marcação de imagens.","frontmatter":{"title":"Funcionalidades da Plataforma: Revisão de Planos e Código | Plannotator","sidebarTitle":"Revisar Planos e Código de IA","subtitle":"Funcionalidades da Plataforma: Revisão de Planos e Código","description":"Aprenda as funcionalidades da plataforma Plannotator, incluindo revisão de planos e revisão de código. Domine habilidades essenciais como revisão visual, adição de anotações e marcação de imagens.","order":2},"headers":[],"relativePath":"pt/backnotprop/plannotator/platforms/index.md","filePath":"pt/backnotprop/plannotator/platforms/index.md"}'),d={name:"pt/backnotprop/plannotator/platforms/index.md"};function t(n,a,s,l,c,p){return i(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="funcionalidades-da-plataforma" tabindex="-1">Funcionalidades da Plataforma <a class="header-anchor" href="#funcionalidades-da-plataforma" aria-label="Permalink to &quot;Funcionalidades da Plataforma&quot;">​</a></h1><p>Este capítulo apresenta as duas funcionalidades principais do Plannotator: <strong>Revisão de Planos</strong> e <strong>Revisão de Código</strong>. Você aprenderá como revisar visualmente os planos gerados por IA, adicionar vários tipos de anotações, anexar marcações de imagem e revisar alterações de código git diff.</p><h2 id="pre-requisitos" tabindex="-1">Pré-requisitos <a class="header-anchor" href="#pre-requisitos" aria-label="Permalink to &quot;Pré-requisitos&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Antes de começar</p><p>Antes de estudar este capítulo, certifique-se de ter concluído as seguintes preparações:</p><ul><li>✅ Concluiu o tutorial de <a href="./../start/getting-started/">Início Rápido</a></li><li>✅ Instalou o plugin Plannotator (<a href="./../start/installation-claude-code/">Claude Code</a> ou <a href="./../start/installation-opencode/">OpenCode</a>)</li></ul></div><h2 id="conteudo-deste-capitulo" tabindex="-1">Conteúdo deste Capítulo <a class="header-anchor" href="#conteudo-deste-capitulo" aria-label="Permalink to &quot;Conteúdo deste Capítulo&quot;">​</a></h2><h3 id="revisao-de-planos" tabindex="-1">Revisão de Planos <a class="header-anchor" href="#revisao-de-planos" aria-label="Permalink to &quot;Revisão de Planos&quot;">​</a></h3><p>Aprenda como revisar planos de execução gerados por IA, adicionar sugestões de modificação e fazer a IA executar de acordo com suas intenções.</p><table tabindex="0"><thead><tr><th>Tutorial</th><th>Descrição</th></tr></thead><tbody><tr><td><a href="./plan-review-basics/">Fundamentos da Revisão de Planos</a></td><td>Aprenda a usar o Plannotator para revisar visualmente planos gerados por IA, incluindo aprovar ou rejeitar planos</td></tr><tr><td><a href="./plan-review-annotations/">Adicionar Anotações ao Plano</a></td><td>Domine como adicionar diferentes tipos de anotações ao plano (excluir, substituir, inserir, comentar)</td></tr><tr><td><a href="./plan-review-images/">Adicionar Marcações de Imagem</a></td><td>Aprenda a anexar imagens na revisão de planos e usar ferramentas de pincel, seta e círculo para marcação</td></tr></tbody></table><h3 id="revisao-de-codigo" tabindex="-1">Revisão de Código <a class="header-anchor" href="#revisao-de-codigo" aria-label="Permalink to &quot;Revisão de Código&quot;">​</a></h3><p>Aprenda como revisar alterações de código, adicionar anotações em nível de linha e identificar problemas antes do commit.</p><table tabindex="0"><thead><tr><th>Tutorial</th><th>Descrição</th></tr></thead><tbody><tr><td><a href="./code-review-annotations/">Adicionar Anotações de Código</a></td><td>Domine como adicionar anotações em nível de linha na revisão de código (comentário/sugestão/preocupação)</td></tr><tr><td><a href="./code-review-diff-types/">Alternar Visualizações de Diff</a></td><td>Aprenda a alternar entre diferentes tipos de diff na revisão de código (uncommitted/staged/último commit/branch)</td></tr></tbody></table><h2 id="caminho-de-aprendizagem" tabindex="-1">Caminho de Aprendizagem <a class="header-anchor" href="#caminho-de-aprendizagem" aria-label="Permalink to &quot;Caminho de Aprendizagem&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Ordem de Aprendizagem Recomendada</p><p>De acordo com seu cenário de uso, escolha o caminho de aprendizagem apropriado:</p><p><strong>Caminho A: Revisão de Planos Prioritária</strong> (Recomendado para iniciantes)</p><ol><li><a href="./plan-review-basics/">Fundamentos da Revisão de Planos</a> → Aprenda primeiro o fluxo básico de revisão de planos</li><li><a href="./plan-review-annotations/">Adicionar Anotações ao Plano</a> → Aprenda como modificar planos com precisão</li><li><a href="./plan-review-images/">Adicionar Marcações de Imagem</a> → Use imagens para expressar intenções mais claramente</li><li>Depois aprenda a série de revisão de código</li></ol><p><strong>Caminho B: Revisão de Código Prioritária</strong> (Adequado para desenvolvedores com experiência em Code Review)</p><ol><li><a href="./code-review-basics/">Fundamentos da Revisão de Código</a> → Familiarize-se com a interface de revisão de código</li><li><a href="./code-review-annotations/">Adicionar Anotações de Código</a> → Aprenda anotações em nível de linha</li><li><a href="./code-review-diff-types/">Alternar Visualizações de Diff</a> → Domine diferentes tipos de diff</li><li>Depois aprenda a série de revisão de planos</li></ol></div><h2 id="proximos-passos" tabindex="-1">Próximos Passos <a class="header-anchor" href="#proximos-passos" aria-label="Permalink to &quot;Próximos Passos&quot;">​</a></h2><p>Após concluir este capítulo, você pode continuar aprendendo:</p><ul><li><a href="./../advanced/url-sharing/">Compartilhamento por URL</a> - Compartilhe planos e anotações por URL para colaboração em equipe</li><li><a href="./../advanced/obsidian-integration/">Integração com Obsidian</a> - Salve automaticamente planos aprovados no Obsidian</li><li><a href="./../advanced/remote-mode/">Modo Remoto</a> - Use o Plannotator em ambientes SSH, devcontainer e WSL</li></ul>',16)])])}const h=e(d,[["render",t]]);export{u as __pageData,h as default};
